#include <bits/stdc++.h>
using namespace std;

double getMaxValue(int n, vector<int>& val, vector<int>& wt, int capacity) {
    vector<pair<double, int>> ratio(n);

    // Calculate value/weight ratio for each item
    for(int i = 0; i < n; i++) {
        ratio[i] = {(double)val[i]/wt[i], i};
    }

    // Sort by ratio in descending order
    sort(ratio.rbegin(), ratio.rend());

    double totalValue = 0.0;
    int currentWeight = 0;

    // Process items in decreasing order of ratio
    for(int i = 0; i < n; i++) {
        int idx = ratio[i].second;

        if(currentWeight + wt[idx] <= capacity) {
            currentWeight += wt[idx];
            totalValue += val[idx];
        }
        else {
            int remainingWeight = capacity - currentWeight;
            totalValue += val[idx] * ((double)remainingWeight/wt[idx]);
            break;
        }
    }

    return totalValue;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n, capacity;
        cin >> n >> capacity;

        vector<int> val(n), wt(n);

        for(int i = 0; i < n; i++) cin >> val[i];
        for(int i = 0; i < n; i++) cin >> wt[i];

        cout << fixed << setprecision(6) << getMaxValue(n, val, wt, capacity) << endl;
    }
    return 0;
}
